def validate_workflow():
    """Validate the workflow file."""
    workflow_path = '.github/workflows/artifact-cleanup-script.yml'

    # Check file exists
    if not os.path.exists(workflow_path):
        print(f"❌ Workflow file not found: {workflow_path}")
